   252→#[async_trait]
   253→impl ChannelEventSink for GatewayChannelEventSink {
   254→    async fn emit(&self, event: ChannelEvent) {
   255→        if let Some(state) = self.state.get() {
   256→            let mut payload = match serde_json::to_value(&event) {
   257→                Ok(v) => v,
   258→                Err(e) => {
   259→                    warn!("failed to serialize channel event: {e}");
   260→                    return;
   261→                },
   262→            };
   263→
   264→            // Fire-and-forget CRM side-effects for inbound messages.
   265→            #[cfg(feature = "crm")]
   266→            if let ChannelEvent::InboundMessage {
   267→                ref channel_type,
   268→                ref peer_id,
   269→                ref username,
   270→                ref sender_name,
   271→                ..
   272→            } = event
   273→                && let Some(crm_store) = self.crm_store.clone()
   274→                && self.crm_config.enabled
   275→            {
   276→                let channel_type = channel_type.as_str().to_string();
   277→                let peer_id = peer_id.clone();
   278→                let username = username.clone();
   279→                let sender_name = sender_name.clone();
   280→                let crm_config = self.crm_config.clone();
   281→                tokio::spawn(handle_crm_inbound(
   282→                    crm_store,
   283→                    crm_config,
   284→                    channel_type,
   285→                    peer_id,
   286→                    username,
   287→                    sender_name,
   288→                ));
   289→            }
   290→
   291→            // Render QR data as an SVG so the frontend can display it directly.
   292→            #[cfg(feature = "whatsapp")]
   293→            if let ChannelEvent::PairingQrCode { ref qr_data, .. } = event
   294→                && let Ok(code) = qrcode::QrCode::new(qr_data)
   295→            {
